import { createClient } from "@supabase/supabase-js";

/**
 * Netlify Function: run-migrations
 *
 * Applies unapplied SQL migrations from _migrations.json.
 * Tracks applied migrations in a `_migrations` table.
 *
 * Env vars required:
 *   SUPABASE_URL             — project URL
 *   SUPABASE_SERVICE_ROLE_KEY — service role key (for DDL)
 *   MIGRATION_SECRET          — bearer token to protect the endpoint
 *
 * POST /.netlify/functions/run-migrations
 * Header: Authorization: Bearer <MIGRATION_SECRET>
 */

// Load bundled migrations — generated by scripts/bundle-migrations.js
let MIGRATIONS = [];
try {
  const { readFileSync } = await import("node:fs");
  const { fileURLToPath } = await import("node:url");
  const { dirname, join } = await import("node:path");
  const __dirname = dirname(fileURLToPath(import.meta.url));
  const raw = readFileSync(join(__dirname, "_migrations.json"), "utf-8");
  MIGRATIONS = JSON.parse(raw);
} catch {
  // No migrations bundled — will return empty
}

function getSupabase() {
  const url = process.env.SUPABASE_URL || process.env.VITE_SUPABASE_URL;
  const key = process.env.SUPABASE_SERVICE_ROLE_KEY;
  if (!url || !key) return null;
  return createClient(url, key);
}

export default async (req) => {
  if (req.method !== "POST") {
    return new Response(JSON.stringify({ error: "POST only" }), { status: 405 });
  }

  // Auth check
  const secret = process.env.MIGRATION_SECRET;
  if (secret) {
    const auth = req.headers.get("authorization") ?? "";
    if (auth !== `Bearer ${secret}`) {
      return new Response(JSON.stringify({ error: "unauthorized" }), { status: 401 });
    }
  }

  const supabase = getSupabase();
  if (!supabase) {
    return new Response(
      JSON.stringify({ error: "SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY not set" }),
      { status: 500 }
    );
  }

  try {
    // Ensure _migrations tracking table exists
    await supabase.rpc("exec_sql", {
      query: `
        CREATE TABLE IF NOT EXISTS _migrations (
          name text PRIMARY KEY,
          applied_at timestamptz DEFAULT NOW()
        );
      `,
    }).then(res => {
      // If RPC doesn't exist, fall back to raw SQL via REST
      if (res.error?.code === "PGRST202") {
        return supabase.from("_migrations").select("name").limit(0);
      }
      return res;
    });

    // Get already-applied migrations
    const { data: applied, error: fetchErr } = await supabase
      .from("_migrations")
      .select("name");

    // If table doesn't exist yet, create it via the first migration approach
    const appliedSet = new Set((applied ?? []).map(r => r.name));

    const pending = MIGRATIONS.filter(m => !appliedSet.has(m.name));

    if (pending.length === 0) {
      return new Response(JSON.stringify({
        status: "up-to-date",
        applied: appliedSet.size,
        total: MIGRATIONS.length,
      }));
    }

    const results = [];
    for (const m of pending) {
      // Split on semicolons to handle multi-statement migrations
      // Filter empty statements
      const statements = m.sql
        .split(/;\s*$/m)
        .map(s => s.trim())
        .filter(s => s.length > 0);

      let migrationError = null;
      for (const stmt of statements) {
        const { error } = await supabase.rpc("exec_sql", { query: stmt + ";" });
        if (error) {
          migrationError = error.message;
          break;
        }
      }

      if (migrationError) {
        results.push({ name: m.name, status: "error", error: migrationError });
        // Stop on first error — don't apply subsequent migrations
        break;
      }

      // Record as applied
      await supabase.from("_migrations").insert({ name: m.name });
      results.push({ name: m.name, status: "applied" });
    }

    return new Response(JSON.stringify({
      status: results.some(r => r.status === "error") ? "partial" : "complete",
      applied: results.filter(r => r.status === "applied").length,
      total: MIGRATIONS.length,
      results,
    }));
  } catch (e) {
    return new Response(JSON.stringify({ error: e.message }), { status: 500 });
  }
};
